sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    g_form.clearOptions('servicenow_priority');
    g_form.setValue('servicenow_priority', '');

    if (!newValue) return;

    g_form.addOption('servicenow_priority', '', '-- Select Priority --');

    var ga = new GlideAjax('PulseCategoryAjax'); // your existing Script Include name
    ga.addParam('sysparm_name', 'getPriorities');

    ga.getXMLAnswer(function (answer) {
        if (!answer) return;

        var items = JSON.parse(answer);
        for (var i = 0; i < items.length; i++) {
            g_form.addOption('servicenow_priority', items[i].value, items[i].label);
        }
    });
}
